#include <stdio.h>
#include <stdlib.h>
#include <limits.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int *A = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        qsort(A, N, sizeof(int), compare);
        int M;
        scanf("%d", &M);
        int minCost = INT_MAX;
        for (int mask = 0; mask < (1 << N); mask++) {
            int cost = 0;
            int count = 0;
            for (int i = 0; i < N; i++) {
                if ((mask & (1 << i)) != 0) {
                    cost += A[i];
                    count++;
                }
            }
            if (count > 1) {
                cost -= A[0];
            }
            minCost = (minCost < cost) ? minCost : cost;
        }
        printf("%d\n", minCost);
        free(A);
    }
    return 0;
}

